import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"리눅스에서 Fabric 업데이트","description":"리눅스에서 Fabric을 업데이트하기 위한 단계별 가이드","frontmatter":{"title":"리눅스에서 Fabric 업데이트","description":"리눅스에서 Fabric을 업데이트하기 위한 단계별 가이드","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"ko_kr/players/updating-fabric/linux.md","filePath":"translated/ko_kr/players/updating-fabric/linux.md","lastUpdated":1772272927000}`);var s={name:`ko_kr/players/updating-fabric/linux.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">리눅스에서 Fabric 업데이트 <a class="header-anchor" href="#h1" aria-label="Permalink to “리눅스에서 Fabric 업데이트”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Fabric 설치기 다운로드 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Fabric 설치기 다운로드”">​</a></h2><p>Fabric 설치기를 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 웹사이트</a>에 접속한 후, <code>설치기 다운로드 (Universal/.JAR)</code> 버튼을 눌러 다운로드하세요. 다운로드하려는 파일 형식은 <code>.jar</code> 입니다.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Fabric 설치기 시작 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Fabric 설치기 시작”">​</a></h2><p>설치기를 시작하기 전에, 먼저 모든 Minecraft 인스턴스와 Minecrft 런처를 종료해야 합니다.</p><p>터미널을 열고 아래 명령어를 실행하세요:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer.jar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>설치기를 실행하면, 아래 사진과 같이 실행됩니다:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="&quot;Install&quot;을 강조 표시한 Fabric 설치기" loading="lazy"></p><p>새 게임 버전과 로더 버전이 일치하는지 확인하고 <code>설치</code>를 눌러 업데이트하세요.</p><div class="warning custom-block"><p class="custom-block-title">중요</p><p>설치기 실행중인 경우 &#39;프로필 생성&#39;을 반드시 비활성화하세요.</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3.”">​</a></h2><p>설치가 끝나면, 마인크래프트 런처를 실행하세요. <code>설치 목록</code> 탭으로 이동합니다. Fabric 프로필을 선택하고 아래와 같이 수정합니다:</p><p><img src="/assets/players/updating-fabric.png" alt="Minecraft 런처에서 Fabric 로더 버전을 변경하는 모습" loading="lazy"></p><p>버전을 방금 설치한 Fabric 로더로 선택한 다음, <code>저장</code>을 클릭합니다.</p><h2 id="4-you-re-done" tabindex="-1">4. 업데이트 완료 <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. 업데이트 완료”">​</a></h2><p>위의 과정을 모두 완료했다면 <code>플레이</code> 탭으로 돌아가서, 왼쪽 아래의 버전 선택 메뉴에서 Fabric을 선택한 다음 플레이를 클릭하면 됩니다.</p><p>설치 과정 중 문제가 발생했다면, <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord (영어)</a>의 <code>#player-support</code> 채널에서 도움을 요청할 수 있습니다.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};